export const pointContent = [{
  id: 1,
  title: "Educational and Professional Background",
  description: "My academic journey began with a Bachelor's degree in Science from the University of Vienna, laying the groundwork for my passion in nutrition. Seeking to deepen my expertise, I pursued a Master's degree at UCM Madrid. My commitment to specialized knowledge led me to also obtain a Master's degree in Football Nutrition, reflecting my keen interest in sports nutrition."
}, {
  id: 2,
  title: "Specialization in Sports Nutrition and Fitness",
  description: "As a specialist in sports nutrition, I understand the critical role that diet plays in athletic performance, endurance, and recovery. My expertise is not limited to dietary advice; I also design customized workout programs. These programs are tailored to complement your nutritional plans, ensuring a holistic approach to your fitness and health goals."
}, {
  id: 3,
  title: "Personal Philosophy and Approach",
  description: "My philosophy centers on offering personalized nutrition and fitness plans, adapted to the unique needs and aspirations of each client. I view each individual's journey as a personal challenge and feel immensely rewarded in helping everyone achieve their goals. The joy of being part of your journey, witnessing each milestone, is what fuels my dedication."
}, {
  id: 4,
  title: "My Personal Transformation",
  description: "My approach is deeply rooted in my own experience. Having been overweight, I embarked on a transformative journey, shedding over 40 kilos through a combination of gym workouts and a complete nutritional overhaul. This personal triumph not only changed my lifestyle but also deepened my understanding and empathy towards others facing similar challenges."
}, {
  id: 5,
  title: "Your Partner in Health and Performance",
  description: "At Nutrition Arvanitis, I bring together a blend of professional expertise and personal experience. Whether you are an athlete looking to optimize your performance, someone seeking to lose weight, or just aiming to improve your overall health, I am here to support and guide you. Together, we will create a harmonious blend of nutrition and exercise that works uniquely for you."
}];

